// src/mcp/tools/list-prompts.tool.ts
var listPromptsInputSchema = external_exports.object({
  category: external_exports.string().optional(),
  ids: external_exports.array(external_exports.string()).optional()
});
var listPromptsToolDefinition = {
  name: "list_security_prompts",
  description: "Return the registry of security prompts (id, title, category, severityFocus, full prompt text) so the CALLING LLM can apply each against scan evidence and reason natively. This is the recommended workflow when the MCP is used from Claude Code or Cursor \u2014 no server-side LLM call is needed.",
  inputSchema: {
    type: "object",
    properties: {
      category: {
        type: "string",
        description: 'Optional. Filter prompts by category (e.g. "auth", "injection").'
      },
      ids: {
        type: "array",
        items: { type: "string" },
        description: "Optional. Return only prompts with these ids."
      }
    }
  }
};
function handleListPrompts(input) {
  let prompts = [...PROMPT_REGISTRY];
  if (input.category) {
    prompts = prompts.filter((p) => p.category === input.category);
  }
  if (input.ids && input.ids.length > 0) {
    const set = new Set(input.ids);
    prompts = prompts.filter((p) => set.has(p.id));
  }
  return {
    count: prompts.length,
    prompts: prompts.map((p) => ({
      id: p.id,
      title: p.title,
      category: p.category,
      severityFocus: p.severityFocus,
      prompt: p.prompt
    })),
    usage: "For each prompt, evaluate it against the evidence object returned by security_scan. Emit findings yourself with the standard shape: { title, severity, confidence, category, description, evidence, impact, remediation }. When done, submit all findings via generate_report."
  };
}

// src/mcp/server.ts
function createMcpServer() {
  const server = new Server(
    { name: "security-mcp", version: "0.1.0" },
    { capabilities: { tools: {} } }
  );
  server.setRequestHandler(ListToolsRequestSchema, async () => ({
    tools: [
      validateTargetToolDefinition,
      securityScanToolDefinition,
      listPromptsToolDefinition,
      promptLoopToolDefinition,
      reportToolDefinition
    ]
  }));
  server.setRequestHandler(CallToolRequestSchema, async (req) => {
    const { name, arguments: args } = req.params;
    try {
      switch (name) {
        case "validate_target": {
          const parsed = validateTargetInputSchema.parse(args ?? {});
          return jsonContent(handleValidateTarget(parsed));
        }
        case "security_scan": {
          const parsed = securityScanInputSchema.parse(args ?? {});
          return jsonContent(await handleSecurityScan(parsed));
        }
        case "list_security_prompts": {
          const parsed = listPromptsInputSchema.parse(args ?? {});
          return jsonContent(handleListPrompts(parsed));
        }
        case "run_prompt_loop": {
          const parsed = promptLoopInputSchema.parse(args ?? {});
          return jsonContent(await handlePromptLoop(parsed));
        }
        case "generate_report": {
          const parsed = reportInputSchema.parse(args ?? {});
          return jsonContent(await handleGenerateReport(parsed));
        }
        default:
          return jsonContent({ ok: false, error: `Unknown tool: ${name}` }, true);
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      return jsonContent({ ok: false, error: message }, true);
    }
  });
  return server;
}
function jsonContent(payload, isError = false) {
  return {
    isError,
    content: [
      {
        type: "text",
        text: JSON.stringify(payload, null, 2)
      }
    ]
  };
}

// src/mcp/http-transport.ts
async function startHttpTransport(_server, _port) {
  throw new Error(
    "HTTP transport scaffold not implemented in V1. See src/mcp/http-transport.ts comments to enable."
  );
}

// src/server.ts
async function main() {
  const env = getEnv();
  const server = createMcpServer();
  if (env.MCP_MODE === "http") {
    await startHttpTransport(server, 3333);
    return;
  }
  const transport = new StdioServerTransport();
  await server.connect(transport);
  process.stderr.write("[security-mcp] stdio transport ready\n");
}
main().catch((err) => {
  process.stderr.write(`[security-mcp] fatal: ${err instanceof Error ? err.stack ?? err.message : String(err)}
`);
  process.exit(1);
});
